B.P7=new A.F(B.k,[u.A,"Studiengang: Wirtschaftsingenieurwesen (B.Sc.)\nProfil: Management elektrischer Systeme"],t.w)
B.Om=new A.F(B.k,[u.g,"Workshop zu 3D-Druck und Laser-Holzschneider"],t.w)
